use sso_protocol::tokens::{OidcSigningKey, create_id_token, create_id_token_with_tier, verify_id_token_with_audience};
static KEY: std::sync::LazyLock<OidcSigningKey> = std::sync::LazyLock::new(|| { std::thread::Builder::new().stack_size(16*1024*1024).spawn(OidcSigningKey::generate).unwrap().join().unwrap() });
fn big<F: FnOnce() + Send + 'static>(f: F) { std::thread::Builder::new().stack_size(16*1024*1024).spawn(f).unwrap().join().unwrap(); }
#[test] fn portal_a_rejected_at_b() { big(|| { let k = &*KEY; let u = uuid::Uuid::new_v4(); let t = create_id_token("https://sso", &u, "A", None, k); assert!(verify_id_token_with_audience(&t, k.verifying_key(), "A", true).is_ok()); let r = verify_id_token_with_audience(&t, k.verifying_key(), "B", true); assert!(r.is_err()); assert!(r.err().unwrap().contains("audience mismatch")); }); }
#[test] fn sso_multi() { big(|| { let k = &*KEY; let u = uuid::Uuid::new_v4(); for p in ["alpha","bravo","charlie"] { let t = create_id_token("https://sso", &u, p, None, k); let c = verify_id_token_with_audience(&t, k.verifying_key(), p, true).unwrap(); assert_eq!(c.sub, u.to_string()); assert_eq!(c.aud, p); } }); }
#[test] fn per_portal_binding() { big(|| { let k = &*KEY; let u = uuid::Uuid::new_v4(); let ta = create_id_token("https://sso", &u, "A", None, k); let tb = create_id_token("https://sso", &u, "B", None, k); assert!(verify_id_token_with_audience(&ta, k.verifying_key(), "A", true).is_ok()); assert!(verify_id_token_with_audience(&ta, k.verifying_key(), "B", true).is_err()); assert!(verify_id_token_with_audience(&tb, k.verifying_key(), "B", true).is_ok()); assert!(verify_id_token_with_audience(&tb, k.verifying_key(), "A", true).is_err()); }); }
#[test] fn tier_across_portals() { big(|| { let k = &*KEY; let u = uuid::Uuid::new_v4(); for t in [1u8,2,3] { let tok = create_id_token_with_tier("https://sso", &u, "A", None, k, t); assert_eq!(verify_id_token_with_audience(&tok, k.verifying_key(), "A", true).unwrap().tier, t); } }); }
